proof_block:
// Bind each sub-expression of the ensures to a ghost boolean so the otherwise
// α-renamed copies of the `forall|i|` that Verus emits for the r1- and r2-
// conjuncts (separate qids in the SMT) collapse to the same SMT term.
let q_inc: bool =
    forall |i: int| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@;
let q_str: bool =
    forall |i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@;
let q_fail: bool =
    self_@[self_.keys@[hi as int]]@ != v@ && q_str;

// Tautological identities that pin each let-bound name to its source-level
// `forall` expression — they teach z3 that the two α-equivalent copies appearing
// in the postcondition's r1- and r2-hypotheses denote the same boolean value.
assert(q_inc ==
    (forall |i: int| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@));
assert(q_str ==
    (forall |i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@));
assert(q_fail ==
    (self_@[self_.keys@[hi as int]]@ != v@
     && (forall |i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@)));

// First component of det_eq: r1.0 and r2.0 are both equal to q_inc, so r1.0 == r2.0.
assert((r1.0 == q_inc && r2.0 == q_inc) ==> r1.0 == r2.0);

// Second component, !r.0 branch: both r1.1 and r2.1 are pinned to q_fail.
assert((r1.0 == q_inc && r2.0 == q_inc
        && (!r1.0 ==> r1.1 == q_fail)
        && (!r2.0 ==> r2.1 == q_fail)
        && !r1.0)
       ==> r1.1 == r2.1);

// Second component, r.0 branch: when r1.0 == r2.0 == q_inc, the spec gives no
// constraint on r1.1 / r2.1 directly. Split on q_inc to expose both cases of
// the conditional ensures to z3 with the same let-bound names.
assert((r1.0 == q_inc && r2.0 == q_inc
        && (!r1.0 ==> r1.1 == q_fail)
        && (!r2.0 ==> r2.1 == q_fail))
       ==> (r1.0 == r2.0
            && (!r1.0 ==> r1.1 == r2.1)
            && (!r2.0 ==> r1.1 == r2.1)));

// Final shape of the implication needed by the postcondition's det_eq:
// r1.0 == r2.0 (always) and r1.1 == r2.1 (whenever !r1.0 || !r2.0).
assert((r1.0 == q_inc && r2.0 == q_inc
        && (!r1.0 ==> r1.1 == q_fail)
        && (!r2.0 ==> r2.1 == q_fail)
        && (!r1.0 || !r2.0))
       ==> ((r1.0 == r2.0) && (r1.1 == r2.1)));
